import java.io.*;
import java.util.*;

public class Main {
    private static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c;
            // skip any non-digit and non-minus characters (including '\n', spaces, '\\', 'n', etc.)
            do {
                c = readByte();
                if (c == -1) return Integer.MIN_VALUE; // EOF
            } while (c != '-' && (c < '0' || c > '9'));
            boolean neg = false;
            if (c == '-') {
                neg = true;
                c = readByte();
            }
            int val = 0;
            while (c >= '0' && c <= '9') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
    }

    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        if (T == Integer.MIN_VALUE) return; // no input
        while (T-- > 0) {
            int N = fs.nextInt();
            int D = fs.nextInt();
            int[] a = new int[N];
            for (int i = 0; i < N; i++) {
                a[i] = fs.nextInt();
            }
            Arrays.sort(a);
            long[] dp = new long[N + 1];
            for (int i = 2; i <= N; i++) {
                dp[i] = dp[i - 1];
                if (a[i - 1] - a[i - 2] < D) {
                    long cand = dp[i - 2] + a[i - 1] + a[i - 2];
                    if (cand > dp[i]) dp[i] = cand;
                }
            }
            out.append(dp[N]).append('\n');
        }
        System.out.print(out.toString());
    }
}

